    public static func lift(_ value: RustBuffer) throws -> CipherId {
        return try FfiConverterTypeUuid_lift(value)
    }

    public static func lower(_ value: CipherId) -> RustBuffer {
        return FfiConverterTypeUuid_lower(value)
